import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Careers = () => {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedJob, setSelectedJob] = useState(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    const fetchJobs = async () => {
      try {
        const res = await axios.get('http://localhost:5001/api/jobs');
        setJobs(res.data);
        setLoading(false);
      } catch (err) {
        console.error("Fetch error:", err);
        setLoading(false);
      }
    };
    fetchJobs();
  }, []);

  return (
    <div className="bg-white font-sans min-h-screen">
      {/* Header */}
      <section className="pt-32 pb-10 px-6 max-w-7xl mx-auto border-b border-gray-100">
        <h2 className="text-5xl font-black text-gray-950 tracking-tighter">Open Positions</h2>
      </section>

      {/* Jobs Listing */}
      <section className="px-6 max-w-7xl mx-auto">
        <div className="divide-y divide-gray-100">
          {loading ? (
            <div className="py-20 text-center animate-pulse text-gray-300 font-bold uppercase tracking-widest">
              Loading Jobs...
            </div>
          ) : jobs.length > 0 ? (
            jobs.map((job) => (
              <div key={job._id} className="grid grid-cols-1 md:grid-cols-12 items-center py-10 hover:bg-gray-50 transition-colors px-4">

                {/* 1. Job Title (Normal Weight) */}
                <div className="md:col-span-5">
                  <h3 className="text-2xl text-gray-700 font-normal tracking-tight">
                    {job.title}
                  </h3>
                </div>

                {/* 2. Location & Salary (Bagal mein with gap) */}
                <div className="md:col-span-4 mt-3 md:mt-0">
                  <div className="flex items-center text-sm font-medium">
                    <span className="text-gray-500 mr-6">📍 {job.loc}</span>
                    <span className="text-gray-300 mr-6">|</span> 
                    <span className="text-gray-400">{job.salary}</span>
                  </div>
                </div>

                {/* 3. Apply Button */}
                <div className="md:col-span-3 mt-6 md:mt-0 text-right">
                  <button 
                    onClick={() => { setSelectedJob(job); setIsFormOpen(true); }}
                    className="w-full md:w-auto bg-gray-950 text-white px-10 py-3.5 rounded-full font-bold text-xs uppercase tracking-widest hover:bg-orange-600 transition-all shadow-lg"
                  >
                    Apply Now
                  </button>
                </div>

              </div>
            ))
          ) : (
            <div className="py-20 text-center text-gray-400 font-medium">
              No openings found.
            </div>
          )}
        </div>
      </section>

      {/* Modal section if you have one... */}
    </div>
  );
};

export default Careers;
